const p="https://eigfbxjheuwxmtdfnvqc.supabase.co/functions/v1/payments";async function s(n){return(await fetch(p,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)})).json()}async function u(n,r){return s({action:"create_unlock_invoice",user_id:n,post_id:r})}async function y(n,r,c,o,e){return s({action:"create_tip_invoice",user_id:n,to_user_id:r,amount:c,message:o,post_id:e})}function l(n,r,c,o){const e=window.Telegram?.WebApp;if(!e){console.error("Telegram WebApp not available"),c?.();return}e.openInvoice(n,i=>{switch(console.log("Invoice status:",i),i){case"paid":r?.();break;case"cancelled":case"failed":c?.();break;case"pending":o?.();break;default:console.log("Unknown invoice status:",i)}})}async function f(n,r,c,o){try{const e=await u(n,r);if(e.error){o?.(e.error);return}if(!e.invoice_link){o?.("Failed to create invoice");return}l(e.invoice_link,c,()=>o?.("Payment was cancelled"),()=>console.log("Payment pending..."))}catch(e){console.error("Unlock payment error:",e),o?.("An error occurred")}}async function d(n,r,c,o,e,i,a){try{const t=await y(n,r,c,o,e);if(t.error){a?.(t.error);return}if(!t.invoice_link){a?.("Failed to create invoice");return}l(t.invoice_link,i,()=>a?.("Payment was cancelled"),()=>console.log("Payment pending..."))}catch(t){console.error("Tip payment error:",t),a?.("An error occurred")}}export{d as s,f as u};
